```rust
fn fib(n: u64) -> u64 {
    let (mut a, mut b) = (0u64, 1u64);
    for _ in 0..n {
        let c = a + b;
        a = b;
        b = c;
    }
    a
}

// 空行也算一行(行窗计数)
fn main() {
    for i in 0..10 {
        println!("fib({i}) = {}", fib(i));
    }
}
```

